import sys
it = iter(sys.stdin.read().split())
try:
    n = int(next(it))
except StopIteration:
    sys.exit()
# read the string token; it may contain no spaces, so next token is the whole string
s = next(it) if n>0 else ""
stack = []
pair = {')':'(',']':'[','}':'{'}
valid = True
for ch in s:
    if ch in '([{':
        stack.append(ch)
    else:
        if not stack or stack[-1] != pair.get(ch):
            valid = False
            break
        stack.pop()
if stack:
    valid = False
sys.stdout.write('True' if valid else 'False')

